insert into public.fruits (
  name_ja,
  name_en,
  slug,
  scientific_name,
  family_name,
  origin,
  description,
  cultivation_summary,
  okinawa_suitability,
  public_notes,
  is_public,
  display_order
)
select
  name_ja,
  name_en,
  slug,
  scientific_name,
  family_name,
  origin,
  description,
  cultivation_summary,
  okinawa_suitability,
  public_notes,
  is_public,
  display_order
from source
on conflict (slug) do nothing;

select count(*) as registered_in_this_part
from public.fruits
where slug in (
  'indian-jujube',
  'durian',
  'sweet-granadilla-vine',
